import { Component, OnInit } from "@angular/core";
import {
  FormBuilder,
  FormControl,
  FormGroup,
  Validators,
} from "@angular/forms";
import { FormStatus } from "src/app/views/Models/forms/formStatus";
import { ReferencesService } from "src/app/core/services/references.service";
import { Funders } from "src/app/views/Models/References/Funders";
import { IOfficer } from "src/app/views/Models/Officer/Officer";
import { IClientType } from "src/app/views/Models/Client/ClientType";
import { LoanType } from "src/app/views/Models/Loan/LoanType";
import { LoanApp } from "src/app/views/Models/Loan/LoanApp";
import { LoanByFunder, LoanInfo } from "src/app/views/Models/Loan/LoanInfo";
import { HttpClient } from "@angular/common/http";
import { EnvService } from "src/app/core/services/env.service";
import { pagingService } from "src/app/core/services/paging.service";
import { sortingService } from "src/app/core/services/sorting.service";
import { AlertService } from "src/app/core/services/alert.service";
import { IBranch } from "src/app/views/Models/References/Branch";
import { InputMaskingService } from "src/app/core/services/input-masking.service";

@Component({
  selector: "app-loan-change-funder",
  templateUrl: "./loan-change-funder.page.html",
  styleUrls: ["./loan-change-funder.page.scss"],
})
export class LoanChangeFunderPage implements OnInit {
  [x: string]: any;
  filterForm: FormGroup;
  funder_code: String;
  all_funder_code: String;
  start_loan_date: String;
  end_loan_date: String;
  loan_am_from: String;
  loan_am_to: String;
  officer_code: String;
  all_officer_code: String;
  client_type_code: String;
  all_client_type_code: String;
  loan_type_code: String;
  all_loan_type_code: String;
  branch_code: string;
  all_branch_code: string;
  LoanByFunder: LoanByFunder[] = [];
  sortingIconClass: string;
  sortingIconParam: string;
  pageSize: number;
  page = 1;
  resultsCount;
  totalPages = 1;
  resultOfInsert;
  pageSizeForSupervised: number;
  pageForSupervised = 1;
  constructor(
    private ReferencesService: ReferencesService,
    private formBuilder: FormBuilder,
    private env: EnvService,
    public pagingService: pagingService,
    private alertService: AlertService,
    private http: HttpClient,
    private sortingService: sortingService,
    public inputMaskingService: InputMaskingService
  ) {}
  showLoader: boolean = false;
  filterFormStatus: FormStatus = { valid: false, visible: true };
  FunderModelResponse: Funders[];
  BranchModelResponse: IBranch[];
  officerModelResponse: IOfficer[];
  CLModelResponse: IClientType[];
  LTModelResponse: LoanType[];
  isUpdating: boolean = false;

  ngOnInit() {
    this.pageSize = this.pagingService.getPageSizeFromLocalStorage();
    this.pageSizeForSupervised =
      this.pagingService.getPageSizeFromLocalStorage();
    this.Load();
    this.filterForm = this.formBuilder.group({
      Branch: ["00"],
      FunderAll: ["00"],
      officer: ["00"],
      ClientType: [""],
      LoanType: ["00"],
      startDate: ["1990-01-01"],
      endDate: [""],
      LoanAmountFrom: [""],
      LoanAmountTo: [""],
      LoanNoFrom: [""],
      LoanNoTo: [""],
    });
    this.FunderForm = this.formBuilder.group({
      FunderAllActive: [""],
      TransActDate: ["", [Validators.required]],
    });
  }

  async Load() {
    this.showLoader = true;
    this.filterFormStatus.valid = true;
    this.filterFormStatus.visible = true;
    this.BranchModelResponse = await this.ReferencesService.GetbranchByUser();
    this.FunderModelResponse = await this.ReferencesService.getAllFunders();
    this.LTModelResponse = await this.ReferencesService.GetAllLoansTypes();
    this.CLModelResponse = await this.ReferencesService.GetClientType();
    //this.officerModelResponse = await this.ReferencesService.GetAllOfficers();
    this.showLoader = false;
  }
  ChangeBranch() {
    this.http
      .get<IOfficer[]>(
        this.env.API_URL +
          "api/Officer/GetOfficerByBranch?branch_code=" +
          this.filterForm.value.Branch,
        {}
      )
      .subscribe((data) => {
        this.officerModelResponse = data;
      });
  }
  async filterSearchBtn() {
    this.showLoader = true;
    this.FunderActiveModelResponse =
      await this.ReferencesService.GetAllFunders();

    if (this.filterForm.valid) {
      if (this.filterForm.value.FunderAll == "00") {
        this.funder_code = "0";
        this.all_funder_code = "1";
      } else {
        this.funder_code = this.filterForm.value.FunderAll;
        this.all_funder_code = "0";
      }
      if (this.filterForm.value.officer == "00") {
        this.officer_code = "0";
        this.all_officer_code = "1";
      } else {
        this.officer_code = this.filterForm.value.officer;
        this.all_officer_code = "0";
      }
      if (this.filterForm.value.ClientType == "00") {
        this.client_type_code = "0";
        this.all_client_type_code = "1";
      } else {
        this.client_type_code = this.filterForm.value.ClientType;
        this.all_client_type_code = "0";
      }
      if (this.filterForm.value.LoanType == "00") {
        this.loan_type_code = "0";
        this.all_loan_type_code = "1";
      } else {
        this.loan_type_code = this.filterForm.value.LoanType;
        this.all_loan_type_code = "0";
      }
      if (this.filterForm.value.LoanNoFrom.toString() == "") {
        this.LoanNoFrom = "0";
      } else {
        this.LoanNoFrom = this.filterForm.value.LoanNoFrom.toString();
      }
      if (this.filterForm.value.LoanNoTo.toString() == "") {
        this.LoanNoTo = "0";
      } else {
        this.LoanNoTo = this.filterForm.value.LoanNoTo.toString();
      }
      if (this.filterForm.value.LoanAmountFrom.toString() == "") {
        this.LoanAmountFrom = "0";
      } else {
        this.LoanAmountFrom = this.filterForm.value.LoanAmountFrom.toString();
      }
      if (this.filterForm.value.LoanAmountTo.toString() == "") {
        this.LoanAmountTo = "0";
      } else {
        this.LoanAmountTo = this.filterForm.value.LoanAmountTo.toString();
      }

      if (this.filterForm.value.Branch == "00") {
        this.branch_code = "0";
        this.all_branch_code = "1";
      } else {
        this.branch_code = this.filterForm.value.Branch;
        this.all_branch_code = "0";
      }

      this.isUpdating = true;

      this.http
        .post<LoanByFunder[]>(
          this.env.API_URL + "api/Settings/GetFunderTypeWithType",
          {
            funder_code: this.funder_code,
            all_funder_code: this.all_funder_code,
            start_loan_date: this.filterForm.value.startDate,
            end_loan_date: this.filterForm.value.endDate,
            loan_am_from: this.LoanAmountFrom.toString(),
            loan_am_to: this.LoanAmountTo.toString(),
            officer_code: this.officer_code,
            all_officer_code: this.all_officer_code,
            prv_no_from: this.LoanNoFrom.toString(),
            prv_no_to: this.LoanNoTo.toString(),
            client_type_code: "0",
            all_client_type_code: "1",
            loan_type_code: this.loan_type_code,
            all_loan_type_code: this.all_loan_type_code,
            branch_code: this.branch_code,
            all_branch_code: this.all_branch_code,
          }
        )
        .subscribe({
          next: (data) => {
            this.LoanByFunder = data;
            this.LoanByFunder.forEach((x) => (x.isCheck = false));

            this.showLoader = false;
          },
          error: (err) => {
            console.log(err);
            this.showLoader = false;
          },
        });
    } else {
      this.alertServices.showAlertError("يجب ادخال جميع البيانات", false);
    }
  }
  paging() {
    this.resultsCount = this.pagingService.totalCount;
    return this.pagingService.Paging(this.LoanByFunder, this.page);
  }
  get isAllSelected(): boolean {
    return this.LoanByFunder.every((x) => x.isCheck);
  }
  changePage(newPage: number): void {
    this.page = newPage;
  }
  onCheckboxChange(event: any, loan: any, index: any) {
    this.LoanByFunder[index + this.pageSize * (this.page - 1)].isCheck =
      event.target.checked;
  }
  sortingTable(data: any, param: string) {
    this.sortingService.sortByParameter(data, param);
    this.sortingIconClass =
      this.sortingService.sortOrder === "asc"
        ? "arrow-down-outline"
        : "arrow-up-outline";
    this.sortingIconParam = param;
  }
  onCheckboxMasterChange(event: any) {
    if (event.target.checked) {
      this.LoanByFunder.forEach(
        (loan) => (loan.isCheck = event.target.checked)
      );
    } else {
      if (this.isAllSelected) {
        this.LoanByFunder.forEach(
          (loan) => (loan.isCheck = event.target.checked)
        );
      }
    }
  }
  async UpdateFunder() {
    //if (this.FunderForm.valid) {
    if (await this.alertService.SaveAlert()) {
      let clients = this.LoanByFunder.filter((x) => x.isCheck === true);
      if (clients.length > 0) {
        this.showLoader = true;
        this.http
          .post(this.env.API_URL + `api/TransType/UpdateFunder`, {
            loan_key: clients.map((x) => x.loan_key.toString()),
            new_funder_code: this.FunderForm.value.FunderAllActive.toString(),
            trans_cr_date: this.FunderForm.value.TransActDate,
          })
          .subscribe({
            next: (data) => {
              this.clearForms();
              this.showLoader = false;
              this.alertService.showAlertConfirm("تم تغير مصدر التمويل ", true);
            },
            error: (err) => {
              this.alertService.showAlertError(err.error, false);
              this.showLoader = false;
            },
          });
      } else {
        this.alertService.showAlertError("لم يتم اختيار قرض", false);
      }
    }
    //}
    //else
    //{
    // this.alertService.showAlertError("يجب اختيار مصدر تمويل", false);
    //}
  }
  clearForms() {
    this.isUpdating = false;
  }
}
